#!/usr/bin/env node
/**
 * Tier 2.5 Test Runner for @microsoft/tui-test
 *
 * This runs outside vitest due to process communication conflicts.
 */

import { tuiTest, KEYS } from '@microsoft/tui-test';
import * as path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const CLI_PATH = path.join(process.cwd(), 'dist', 'cli.js');

// Simple test runner
let passed = 0;
let failed = 0;
const errors = [];

async function test(name, fn) {
  try {
    await fn();
    console.log(`✅ ${name}`);
    passed++;
  } catch (error) {
    console.log(`❌ ${name}`);
    console.log(`   Error: ${error.message}`);
    errors.push({ name, error });
    failed++;
  }
}

console.log('╔════════════════════════════════════════════════════════════╗');
console.log('║  Tier 2.5: TUI Integration (@microsoft/tui-test)          ║');
console.log('╚════════════════════════════════════════════════════════════╝');
console.log();

await test('should display welcome message on startup', async () => {
  await tuiTest(async (session) => {
    await session.start(`node ${CLI_PATH}`);
    await session.waitForText('Welcome to chipilot');
  }, 10000);
});

await test('should show help hint in header', async () => {
  await tuiTest(async (session) => {
    await session.start(`node ${CLI_PATH}`);
    await session.waitForText('Welcome to chipilot');

    const hasTab = await session.hasText('Tab: switch');
    const hasHelp = await session.hasText('?: help');

    if (!hasTab || !hasHelp) {
      throw new Error('Missing header hints');
    }
  }, 10000);
});

await test('should accept and display typed input', async () => {
  await tuiTest(async (session) => {
    await session.start(`node ${CLI_PATH}`);
    await session.waitForText('Welcome');

    await session.type('hello world');

    const hasText = await session.hasText('hello world');
    if (!hasText) {
      throw new Error('Typed text not found');
    }
  }, 10000);
});

await test('should switch to terminal pane with Tab', async () => {
  await tuiTest(async (session) => {
    await session.start(`node ${CLI_PATH}`);
    await session.waitForText('Welcome');

    await session.keyPress(KEYS.TAB);
    await session.waitForText('Tab to return to chat');
  }, 10000);
});

await test('should preserve input when switching panes', async () => {
  await tuiTest(async (session) => {
    await session.start(`node ${CLI_PATH}`);
    await session.waitForText('Welcome');

    await session.type('preserved message');
    await session.keyPress(KEYS.TAB);
    await session.waitForText('Tab to return to chat');

    const screen = await session.getScreen();
    if (screen.includes('preserved message')) {
      throw new Error('Input visible in terminal pane (should be hidden)');
    }

    await session.keyPress(KEYS.TAB);

    const hasText = await session.hasText('preserved message');
    if (!hasText) {
      throw new Error('Input not preserved after switching back');
    }
  }, 10000);
});

await test('should show help overlay with ? key', async () => {
  await tuiTest(async (session) => {
    await session.start(`node ${CLI_PATH}`);
    await session.waitForText('Welcome');

    await session.type('?');
    await session.waitForText('Keyboard Shortcuts');
  }, 10000);
});

console.log();
console.log('═'.repeat(60));
console.log(`Results: ${passed} passed, ${failed} failed`);
console.log('═'.repeat(60));

if (errors.length > 0) {
  console.log('\nErrors:');
  for (const { name, error } of errors) {
    console.log(`  - ${name}: ${error.message}`);
  }
}

process.exit(failed > 0 ? 1 : 0);
